/** Quick lookup by id */
export function getChapterById(id) {
  return CHAPTERS.find(c => c.id === id) || null
}

/** Get all chapters for a given part */
export function getChaptersByPart(partId) {
  return CHAPTERS.filter(c => c.partId === partId)
}

/** Total Q&A count across all chapters */
export const TOTAL_QA_COUNT = CHAPTERS.reduce((sum, c) => sum + c.qaCount, 0)
